import type { BibleBook } from '../bibleData';

// Auto-generated from public-domain sources: World English Bible (WEB, EN)
// and João Ferreira de Almeida (Almeida, PT), via seven1m/open-bibles (USFX).
// Do not edit by hand — regenerate with scripts/generate-bible.

const book: BibleBook = {
  id: 'lamentations',
  name: 'Lamentações',
  englishName: 'Lamentations',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'How the city sits solitary, that was full of people! She has become as a widow, who was great among the nations! She who was a princess among the provinces has become a slave!', pt: 'Como está sentada solitária a cidade que era tão populosa! tornou-se como viúva a que era grande entre as nações! A que era princesa entre as províncias tornou-se avassalada!' },
      { v: 2, en: 'She weeps bitterly in the night. Her tears are on her cheeks. Among all her lovers she has no one to comfort her. All her friends have dealt treacherously with her. They have become her enemies.', pt: 'Chora amargamente de noite, e as lágrimas lhe correm pelas faces; não tem quem a console entre todos os seus amantes; todos os seus amigos se houveram aleivosamente com ela; tornaram-se seus inimigos.' },
      { v: 3, en: 'Judah has gone into captivity because of affliction, and because of great servitude. She dwells among the nations. She finds no rest. All her persecutors overtook her within the straits.', pt: 'Judá foi para o cativeiro para sofrer aflição e dura servidão; ela habita entre as nações, não acha descanso; todos os seus perseguidores a alcançaram nas suas angústias.' },
      { v: 4, en: 'The roads to Zion mourn, because no one comes to the solemn assembly. All her gates are desolate. Her priests sigh. Her virgins are afflicted, and she herself is in bitterness.', pt: 'Os caminhos de Sião pranteiam, porque não há quem venha à assembléia solene; todas as suas portas estão desoladas; os seus sacerdotes suspiram; as suas virgens estão tristes, e ela mesma sofre amargamente.' },
      { v: 5, en: 'Her adversaries have become the head. Her enemies prosper; for Yahweh has afflicted her for the multitude of her transgressions. Her young children have gone into captivity before the adversary.', pt: 'Os seus adversários a dominam, os seus inimigos prosperam; porque o Senhor a afligiu por causa da multidão das suas transgressões; os seus filhinhos marcharam para o cativeiro adiante do adversário.' },
      { v: 6, en: 'All majesty has departed from the daughter of Zion. Her princes have become like deer that find no pasture. They have gone without strength before the pursuer.', pt: 'E da filha de Sião já se foi todo o seu esplendor; os seus príncipes ficaram sendo como cervos que não acham pasto e caminham sem força adiante do perseguidor.' },
      { v: 7, en: 'Jerusalem remembers in the days of her affliction and of her miseries all her pleasant things that were from the days of old; when her people fell into the hand of the adversary, and no one helped her. The adversaries saw her. They mocked at her desolations.', pt: 'Lembra-se Jerusalém, nos dias da sua aflição e dos seus exílios, de todas as suas preciosas coisas, que tivera desde os tempos antigos; quando caía o seu povo na mão do adversário, e não havia quem a socorresse, os adversários a viram, e zombaram da sua ruína.' },
      { v: 8, en: 'Jerusalem has grievously sinned. Therefore she has become unclean. All who honored her despise her, because they have seen her nakedness. Yes, she sighs, and turns backward.', pt: 'Jerusalém gravemente pecou, por isso se fez imunda; todos os que a honravam a desprezam, porque lhe viram a nudez; ela também suspira e se volta para trás.' },
      { v: 9, en: 'Her filthiness was in her skirts. She didn’t remember her latter end. Therefore she has come down astoundingly. She has no comforter. “See, Yahweh, my affliction; for the enemy has magnified himself.”', pt: 'A sua imundícia estava nas suas fraldas; não se lembrava do seu fim; por isso foi espantosamente abatida; não há quem a console; vê, Senhor, a minha aflição; pois o inimigo se tem engrandecido.' },
      { v: 10, en: 'The adversary has spread out his hand on all her pleasant things; for she has seen that the nations have entered into her sanctuary, concerning whom you commanded that they should not enter into your assembly.', pt: 'Estendeu o adversário a sua mão a todas as coisas preciosas dela; pois ela viu entrar no seu santuário as nações, acerca das quais ordenaste que não entrassem na tua congregação.' },
      { v: 11, en: 'All her people sigh. They seek bread. They have given their pleasant things for food to refresh their soul. “Look, Yahweh, and see; for I have become despised.”', pt: 'Todo o seu povo anda gemendo, buscando o pão; deram as suas coisas mais preciosas a troco de mantimento para refazerem as suas forças. Vê, Senhor, e contempla, pois me tornei desprezível.' },
      { v: 12, en: '“Is it nothing to you, all you who pass by? Look, and see if there is any sorrow like my sorrow, which is brought on me, with which Yahweh has afflicted me in the day of his fierce anger.', pt: 'Não vos comove isto a todos vós que passais pelo caminho? Atendei e vede se há dor igual a minha dor, que veio sobre mim, com que o Senhor me afligiu, no dia do furor da sua ira.' },
      { v: 13, en: '“From on high has he sent fire into my bones, and it prevails against them. He has spread a net for my feet. He has turned me back. He has made me desolate and I faint all day long.', pt: 'Desde o alto enviou fogo que entra nos meus ossos, o qual se assenhoreou deles; estendeu uma rede aos meus pés, fez-me voltar para trás, tornou-me desolada e desfalecida o dia todo.' },
      { v: 14, en: '“The yoke of my transgressions is bound by his hand. They are knit together. They have come up on my neck. He made my strength fail. The Lord has delivered me into their hands, against whom I am not able to stand.', pt: 'O jugo das minhas transgressões foi atado; pela sua mão elas foram entretecidas e postas sobre o meu pescoço; ele abateu a minha força; entregou-me o Senhor nas mãos daqueles a quem eu não posso resistir.' },
      { v: 15, en: '“The Lord has set at nothing all my mighty men within me. He has called a solemn assembly against me to crush my young men. The Lord has trodden the virgin daughter of Judah as in a wine press.', pt: 'O Senhor desprezou todos os meus valentes no meio de mim; convocou contra mim uma assembléia para esmagar os meus mancebos; o Senhor pisou como num lagar a virgem filha de Judá.' },
      { v: 16, en: '“For these things I weep. My eye, my eye runs down with water, because the comforter who should refresh my soul is far from me. My children are desolate, because the enemy has prevailed.”', pt: 'Por estas coisas vou chorando; os meus olhos, os meus olhos se desfazem em águas; porque está longe de mim um consolador que pudesse renovar o meu ânimo; os meus filhos estão desolados, porque prevaleceu o inimigo.' },
      { v: 17, en: 'Zion spreads out her hands. There is no one to comfort her. Yahweh has commanded concerning Jacob, that those who are around him should be his adversaries. Jerusalem is among them as an unclean thing.', pt: 'Estende Sião as suas mãos, não há quem a console; ordenou o Senhor acerca de Jacó que fossem inimigos os que estão em redor dele; Jerusalém se tornou entre eles uma coisa imunda.' },
      { v: 18, en: '“Yahweh is righteous; for I have rebelled against his commandment. Please hear all you peoples, and see my sorrow. My virgins and my young men have gone into captivity.', pt: 'Justo é o Senhor, pois me rebelei contra os seus mandamentos; ouvi, rogo-vos, todos os povos, e vede a minha dor; para o cativeiro foram-se as minhas virgens e os meus mancebos.' },
      { v: 19, en: '“I called for my lovers, but they deceived me. My priests and my elders gave up the spirit in the city, while they sought food for themselves to refresh their souls.', pt: 'Chamei os meus amantes, mas eles me enganaram; os meus sacerdotes e os meus anciãos expiraram na cidade, enquanto buscavam para si mantimento, para refazerem as suas forças.' },
      { v: 20, en: '“Look, Yahweh; for I am in distress. My heart is troubled. My heart turns over within me, for I have grievously rebelled. Abroad, the sword bereaves. At home, it is like death.', pt: 'Olha, Senhor, porque estou angustiada; turbadas estão as minhas entranhas; o meu coração está transtornado dentro de mim; porque gravemente me rebelei. Na rua me desfilha a espada, em casa é como a morte.' },
      { v: 21, en: '“They have heard that I sigh. There is no one to comfort me. All my enemies have heard of my trouble. They are glad that you have done it. You will bring the day that you have proclaimed, and they will be like me.', pt: 'Ouviram como estou gemendo; mas não há quem me console; todos os meus inimigos souberam do meu mal; alegram-se de que tu o determinaste; mas, em trazendo tu o dia que anunciaste, eles se tornarão semelhantes a mim.' },
      { v: 22, en: '“Let all their wickedness come before you. Do to them as you have done to me for all my transgressions. For my sighs are many, and my heart is faint.', pt: 'Venha toda a sua maldade para a tua presença, e faze-lhes como me fizeste a mim por causa de todas as minhas transgressões; pois muitos são os meus gemidos, e desfalecido está o meu coração.' },
    ],
    2: [
      { v: 1, en: 'How has the Lord covered the daughter of Zion with a cloud in his anger! He has cast the beauty of Israel down from heaven to the earth, and hasn’t remembered his footstool in the day of his anger.', pt: 'Como cobriu o Senhor de nuvens na sua ira a filha de Sião! derrubou do céu à terra a glória de Israel, e no dia da sua ira não se lembrou do escabelo de seus pés.' },
      { v: 2, en: 'The Lord has swallowed up all the dwellings of Jacob without pity. He has thrown down in his wrath the strongholds of the daughter of Judah. He has brought them down to the ground. He has profaned the kingdom and its princes.', pt: 'Devorou o Senhor sem piedade todas as moradas de Jacó; derrubou no seu furor as fortalezas da filha de Judá; abateu-as até a terra. Tratou como profanos o reino e os seus príncipes.' },
      { v: 3, en: 'He has cut off all the horn of Israel in fierce anger. He has drawn back his right hand from before the enemy. He has burned up Jacob like a flaming fire, which devours all around.', pt: 'No furor da sua ira cortou toda a força de Israel; retirou para trás a sua destra de diante do inimigo; e ardeu contra Jacó, como labareda de fogo que tudo consome em redor.' },
      { v: 4, en: 'He has bent his bow like an enemy. He has stood with his right hand as an adversary. Has killed all that were pleasant to the eye. In the tent of the daughter of Zion, he has poured out his wrath like fire.', pt: 'Armou o seu arco como inimigo, firmou a sua destra como adversário, e matou todo o que era formoso aos olhos; derramou a sua indignação como fogo na tenda da filha de Sião.' },
      { v: 5, en: 'The Lord has become as an enemy. He has swallowed up Israel. He has swallowed up all her palaces. He has destroyed his strongholds. He has multiplied mourning and lamentation in the daughter of Judah.', pt: 'Tornou-se o Senhor como inimigo; devorou a Israel, devorou todos os seus palácios, destruiu as suas fortalezas, e multiplicou na filha de Judá o pranto e a lamentação.' },
      { v: 6, en: 'He has violently taken away his tabernacle, as if it were of a garden. He has destroyed his place of assembly. Yahweh has caused solemn assembly and Sabbath to be forgotten in Zion. In the indignation of his anger, he has despised the king and the priest.', pt: 'E arrancou a sua cabana com violência, como se fosse a de uma horta; destruiu o seu lugar de assembléia; o Senhor entregou ao esquecimento em Sião a assembléia solene e o sábado; e na indignação da sua ira rejeitou com desprezo o rei e o sacerdote.' },
      { v: 7, en: 'The Lord has cast off his altar. He has abhorred his sanctuary. He has given the walls of her palaces into the hand of the enemy. They have made a noise in Yahweh’s house, as in the day of a solemn assembly.', pt: 'Desprezou o Senhor o seu altar, detestou o seu santuário; entregou na mão do inimigo os muros dos seus palácios; deram-se gritos na casa do Senhor, como em dia de reunião solene.' },
      { v: 8, en: 'Yahweh has purposed to destroy the wall of the daughter of Zion. He has stretched out the line. He has not withdrawn his hand from destroying; He has made the rampart and wall lament. They languish together.', pt: 'Resolveu o Senhor destruir o muro da filha de Sião; estendeu o cordel, não reteve a sua mão de fazer estragos; fez gemer o antemuro e o muro; eles juntamente se enfraquecem.' },
      { v: 9, en: 'Her gates have sunk into the ground. He has destroyed and broken her bars. Her king and her princes are among the nations where the law is not. Yes, her prophets find no vision from Yahweh.', pt: 'Sepultadas na terra estão as suas portas; ele destruiu e despedaçou os ferrolhos dela; o seu rei e os seus príncipes estão entre as nações; não há lei; também os seus profetas não recebem visão alguma da parte do Senhor.' },
      { v: 10, en: 'The elders of the daughter of Zion sit on the ground. They keep silence. They have cast up dust on their heads. They have clothed themselves with sackcloth. The virgins of Jerusalem hang down their heads to the ground.', pt: 'Estão sentados no chão os anciãos da filha de Sião, e ficam calados; lançaram pó sobre as suas cabeças; cingiram sacos; as virgens de Jerusalém abaixaram as suas cabeças até o chão.' },
      { v: 11, en: 'My eyes fail with tears. My heart is troubled. My liver is poured on the earth, because of the destruction of the daughter of my people, because the young children and the infants swoon in the streets of the city.', pt: 'Já se consumiram os meus olhos com lágrimas, turbada está a minha alma, o meu coração se derrama de tristeza por causa do quebrantamento da filha do meu povo; porquanto desfalecem os meninos e as crianças de peito pelas ruas da cidade.' },
      { v: 12, en: 'They ask their mothers, “Where is grain and wine?” when they swoon as the wounded in the streets of the city, when their soul is poured out into their mothers’ bosom.', pt: 'Ao desfalecerem, como feridos, pelas ruas da cidade, ao exalarem as suas almas no regaço de suas mães, perguntam a elas: Onde está o trigo e o vinho?' },
      { v: 13, en: 'What shall I testify to you? What shall I liken to you, daughter of Jerusalem? What shall I compare to you, that I may comfort you, virgin daughter of Zion? For your breach is as big as the sea. Who can heal you?', pt: 'Que testemunho te darei, a que te compararei, ó filha de Jerusalém? A quem te assemelharei, para te consolar, ó virgem filha de Sião? pois grande como o mar é a tua ferida; quem te poderá curar?' },
      { v: 14, en: 'Your prophets have seen false and foolish visions for you. They have not uncovered your iniquity, to reverse your captivity, but have seen for you false revelations and causes of banishment.', pt: 'Os teus profetas viram para ti visões falsas e insensatas; e não manifestaram a tua iniqüidade, para te desviarem do cativeiro; mas viram para ti profecias vãs e coisas que te levaram ao exílio.' },
      { v: 15, en: 'All that pass by clap their hands at you. They hiss and wag their head at the daughter of Jerusalem, saying, “Is this the city that men called ‘The perfection of beauty, the joy of the whole earth’?”', pt: 'Todos os que passam pelo caminho batem palmas contra ti; eles assobiam e meneiam a cabeça sobre a filha de Jerusalém, dizendo: E esta a cidade que denominavam a perfeição da formosura, o gozo da terra toda?' },
      { v: 16, en: 'All your enemies have opened their mouth wide against you. They hiss and gnash their teeth. They say, “We have swallowed her up. Certainly this is the day that we looked for. We have found it. We have seen it.”', pt: 'Todos os teus inimigos abrem as suas bocas contra ti, assobiam, e rangem os dentes; dizem: Devoramo-la; certamente este e o dia que esperavamos; achamo-lo, vimo-lo.' },
      { v: 17, en: 'Yahweh has done that which he planned. He has fulfilled his word that he commanded in the days of old. He has thrown down, and has not pitied. He has caused the enemy to rejoice over you. He has exalted the horn of your adversaries.', pt: 'Fez o Senhor o que intentou; cumpriu a sua palavra, que ordenou desde os dias da antigüidade; derrubou, e não se apiedou; fez que o inimigo se alegrasse por tua causa, exaltou o poder dos teus adversários.' },
      { v: 18, en: 'Their heart cried to the Lord. O wall of the daughter of Zion, let tears run down like a river day and night. Give yourself no relief. Don’t let the your eyes rest.', pt: 'Clama ao Senhor, ó filha de Sião; corram as tuas lágrimas, como um ribeiro, de dia e de noite; não te dês repouso, nem descansem os teus olhos.' },
      { v: 19, en: 'Arise, cry out in the night, at the beginning of the watches! Pour out your heart like water before the face of the Lord. Lift up your hands toward him for the life of your young children, who faint for hunger at the head of every street.', pt: 'Levanta-te, clama de noite no princípio das vigias; derrama o teu coração como águas diante do Senhor! Levanta a ele as tuas mãos, pela vida de teus filhinhos, que desfalecem de fome à entrada de todas as ruas.' },
      { v: 20, en: '“Look, Yahweh, and see to whom you have done thus! Should the women eat their offspring, the children that they held and bounced on their knees? Should the priest and the prophet be killed in the sanctuary of the Lord?', pt: 'Vê, ó Senhor, e considera a quem assim tens tratado! Acaso comerão as mulheres o fruto de si mesmas, as crianças que trazem nos braços? ou matar-se-á no santuário do Senhor o sacerdote e o profeta?' },
      { v: 21, en: '“The youth and the old man lie on the ground in the streets. My virgins and my young men have fallen by the sword. You have killed them in the day of your anger. You have slaughtered, and not pitied.', pt: 'Jazem por terra nas ruas o moço e o velho; as minhas virgens e os meus jovens vieram a cair à espada; tu os mataste no dia da tua ira; trucidaste-os sem misericórdia.' },
      { v: 22, en: '“You have called, as in the day of a solemn assembly, my terrors on every side. There was no one that escaped or remained in the day of Yahweh’s anger. My enemy has consumed those whom I have cared for and brought up.', pt: 'Convocaste de toda a parte os meus terrores, como no dia de assembléia solene; não houve no dia da ira do Senhor quem escapasse ou ficasse; aqueles que eu trouxe nas mãos e criei, o meu inimigo os consumiu.' },
    ],
    3: [
      { v: 1, en: 'I am the man who has seen affliction by the rod of his wrath.', pt: 'Eu sou o homem que viu a aflição causada pela vara do seu furor.' },
      { v: 2, en: 'He has led me and caused me to walk in darkness, and not in light.', pt: 'Ele me guiou e me fez andar em trevas e não na luz.' },
      { v: 3, en: 'Surely he turns his hand against me again and again all day long.', pt: 'Deveras fez virar e revirar a sua mão contra mim o dia todo.' },
      { v: 4, en: 'He has made my flesh and my skin old. He has broken my bones.', pt: 'Fez envelhecer a minha carne e a minha pele; quebrou-me os ossos.' },
      { v: 5, en: 'He has built against me, and surrounded me with bitterness and hardship.', pt: 'Levantou trincheiras contra mim, e me cercou de fel e trabalho.' },
      { v: 6, en: 'He has made me dwell in dark places, as those who have been long dead.', pt: 'Fez-me habitar em lugares tenebrosos, como os que estavam mortos há muito.' },
      { v: 7, en: 'He has walled me about, so that I can’t go out. He has made my chain heavy.', pt: 'Cercou-me de uma sebe de modo que não posso sair; agravou os meus grilhões.' },
      { v: 8, en: 'Yes, when I cry, and call for help, he shuts out my prayer.', pt: 'Ainda quando grito e clamo por socorro, ele exclui a minha oração.' },
      { v: 9, en: 'He has walled up my ways with cut stone. He has made my paths crooked.', pt: 'Fechou os meus caminhos com pedras lavradas, fez tortuosas as minhas veredas.' },
      { v: 10, en: 'He is to me as a bear lying in wait, as a lion in secret places.', pt: 'Fez-se-me como urso de emboscada, um leão em esconderijos.' },
      { v: 11, en: 'He has turned away my ways, and pulled me in pieces. He has made me desolate.', pt: 'Desviou os meus caminhos, e fez-me em pedaços; deixou-me desolado.' },
      { v: 12, en: 'He has bent his bow, and set me as a mark for the arrow.', pt: 'Armou o seu arco, e me pôs como alvo à flecha.' },
      { v: 13, en: 'He has caused the shafts of his quiver to enter into my kidneys.', pt: 'Fez entrar nos meus rins as flechas da sua aljava.' },
      { v: 14, en: 'I have become a derision to all my people, and their song all day long.', pt: 'Fui feito um objeto de escárnio para todo o meu povo, e a sua canção o dia todo.' },
      { v: 15, en: 'He has filled me with bitterness. He has stuffed me with wormwood.', pt: 'Encheu-me de amarguras, fartou-me de absinto.' },
      { v: 16, en: 'He has also broken my teeth with gravel. He has covered me with ashes.', pt: 'Quebrou com pedrinhas de areia os meus dentes, cobriu-me de cinza.' },
      { v: 17, en: 'You have removed my soul far away from peace. I forgot prosperity.', pt: 'Alongaste da paz a minha alma; esqueci-me do que seja a felicidade.' },
      { v: 18, en: 'I said, “My strength has perished, along with my expectation from Yahweh.”', pt: 'Digo, pois: Já pereceu a minha força, como também a minha esperança no Senhor.' },
      { v: 19, en: 'Remember my affliction and my misery, the wormwood and the bitterness.', pt: 'Lembra-te da minha aflição e amargura, do absinto e do fel.' },
      { v: 20, en: 'My soul still remembers them, and is bowed down within me.', pt: 'Minha alma ainda os conserva na memória, e se abate dentro de mim.' },
      { v: 21, en: 'This I recall to my mind; therefore I have hope.', pt: 'Torno a trazer isso à mente, portanto tenho esperança.' },
      { v: 22, en: 'It is because of Yahweh’s loving kindnesses that we are not consumed, because his compassion doesn’t fail.', pt: 'A benignidade do Senhor jamais acaba, as suas misericórdias não têm fim;' },
      { v: 23, en: 'They are new every morning. Great is your faithfulness.', pt: 'renovam-se cada manhã. Grande é a tua fidelidade.' },
      { v: 24, en: '“Yahweh is my portion,” says my soul. “Therefore I will hope in him.”', pt: 'A minha porção é o Senhor, diz a minha alma; portanto esperarei nele.' },
      { v: 25, en: 'Yahweh is good to those who wait for him, to the soul who seeks him.', pt: 'Bom é o Senhor para os que esperam por ele, para a alma que o busca.' },
      { v: 26, en: 'It is good that a man should hope and quietly wait for the salvation of Yahweh.', pt: 'Bom é ter esperança, e aguardar em silêncio a salvação do Senhor.' },
      { v: 27, en: 'It is good for a man that he bear the yoke in his youth.', pt: 'Bom é para o homem suportar o jugo na sua mocidade.' },
      { v: 28, en: 'Let him sit alone and keep silence, because he has laid it on him.', pt: 'Que se assente ele, sozinho, e fique calado, porquanto Deus o pôs sobre ele.' },
      { v: 29, en: 'Let him put his mouth in the dust, if it is so that there may be hope.', pt: 'Ponha a sua boca no pó; talvez ainda haja esperança.' },
      { v: 30, en: 'Let him give his cheek to him who strikes him. Let him be filled full of reproach.', pt: 'Dê a sua face ao que o fere; farte-se de afronta.' },
      { v: 31, en: 'For the Lord will not cast off forever.', pt: 'Pois o Senhor não rejeitará para sempre.' },
      { v: 32, en: 'For though he causes grief, yet he will have compassion according to the multitude of his loving kindnesses.', pt: 'Embora entristeça a alguém, contudo terá compaixão segundo a grandeza da sua misericordia.' },
      { v: 33, en: 'For he does not afflict willingly, nor grieve the children of men.', pt: 'Porque não aflige nem entristece de bom grado os filhos dos homens.' },
      { v: 34, en: 'To crush under foot all the prisoners of the earth,', pt: 'Pisar debaixo dos pés a todos os presos da terra,' },
      { v: 35, en: 'to turn away the right of a man before the face of the Most High,', pt: 'perverter o direito do homem perante a face do Altíssimo,' },
      { v: 36, en: 'to subvert a man in his cause, the Lord doesn’t approve.', pt: 'subverter o homem no seu pleito, não são do agrado do senhor.' },
      { v: 37, en: 'Who is he who says, and it comes to pass, when the Lord doesn’t command it?', pt: 'Quem é aquele que manda, e assim acontece, sem que o Senhor o tenha ordenado?' },
      { v: 38, en: 'Doesn’t evil and good come out of the mouth of the Most High?', pt: 'Não sai da boca do Altíssimo tanto o mal como o bem?' },
      { v: 39, en: 'Why does a living man complain, a man for the punishment of his sins?', pt: 'Por que se queixaria o homem vivente, o varão por causa do castigo dos seus pecados?' },
      { v: 40, en: 'Let us search and try our ways, and turn again to Yahweh.', pt: 'Esquadrinhemos os nossos caminhos, provemo-los, e voltemos para o Senhor.' },
      { v: 41, en: 'Let us lift up our heart with our hands to God in the heavens.', pt: 'Levantemos os nossos corações com as mãos para Deus no céu dizendo;' },
      { v: 42, en: '“We have transgressed and have rebelled. You have not pardoned.', pt: 'Nós transgredimos, e fomos rebeldes, e não perdoaste,' },
      { v: 43, en: '“You have covered us with anger and pursued us. You have killed. You have not pitied.', pt: 'Cobriste-te de ira, e nos perseguiste; mataste, não te apiedaste.' },
      { v: 44, en: 'You have covered yourself with a cloud, so that no prayer can pass through.', pt: 'Cobriste-te de nuvens, para que não passe a nossa oração.' },
      { v: 45, en: 'You have made us an off-scouring and refuse in the middle of the peoples.', pt: 'Como escória e refugo nos puseste no meio dos povos.' },
      { v: 46, en: '“All our enemies have opened their mouth wide against us.', pt: 'Todos os nossos inimigos abriram contra nós a sua boca.' },
      { v: 47, en: 'Terror and the pit have come on us, devastation and destruction.”', pt: 'Temor e cova vieram sobre nós, assolação e destruição.' },
      { v: 48, en: 'My eye runs down with streams of water, for the destruction of the daughter of my people.', pt: 'Torrentes de águas correm dos meus olhos, por causa da destruição da filha do meu povo.' },
      { v: 49, en: 'My eye pours down and doesn’t cease, without any intermission,', pt: 'Os meus olhos derramam lágrimas, e não cessam, sem haver intermissão,' },
      { v: 50, en: 'until Yahweh looks down, and sees from heaven.', pt: 'até que o Senhor atente e veja desde o céu.' },
      { v: 51, en: 'My eye affects my soul, because of all the daughters of my city.', pt: 'Os meus olhos me afligem, por causa de todas as filhas da minha cidade.' },
      { v: 52, en: 'They have chased me relentlessly like a bird, those who are my enemies without cause.', pt: 'Como ave me caçaram os que, sem causa, são meus inimigos.' },
      { v: 53, en: 'They have cut off my life in the dungeon, and have cast a stone on me.', pt: 'Atiraram-me vivo na masmorra, e lançaram pedras sobre mim.' },
      { v: 54, en: 'Waters flowed over my head. I said, “I am cut off.”', pt: 'Águas correram sobre a minha cabeça; eu disse: Estou cortado.' },
      { v: 55, en: 'I called on your name, Yahweh, out of the lowest dungeon.', pt: 'Invoquei o teu nome, Senhor, desde a profundeza da masmorra.' },
      { v: 56, en: 'You heard my voice: “Don’t hide your ear from my sighing, and my cry.”', pt: 'Ouviste a minha voz; não escondas o teu ouvido ao meu suspiro, ao meu clamor.' },
      { v: 57, en: 'You came near in the day that I called on you. You said, “Don’t be afraid.”', pt: 'Tu te aproximaste no dia em que te invoquei; disseste: Não temas.' },
      { v: 58, en: 'Lord, you have pleaded the causes of my soul. You have redeemed my life.', pt: 'Pleiteaste, Senhor, a minha causa; remiste a minha vida.' },
      { v: 59, en: 'Yahweh, you have seen my wrong. Judge my cause.', pt: 'Viste, Senhor, a injustiça que sofri; julga tu a minha causa.' },
      { v: 60, en: 'You have seen all their vengeance and all their plans against me.', pt: 'Viste toda a sua vingança, todos os seus desígnios contra mim.' },
      { v: 61, en: 'You have heard their reproach, Yahweh, and all their plans against me,', pt: 'Ouviste as suas afrontas, Senhor, todos os seus desígnios contra mim,' },
      { v: 62, en: 'the lips of those that rose up against me, and their plots against me all day long.', pt: 'os lábios e os pensamentos dos que se levantam contra mim o dia todo.' },
      { v: 63, en: 'You see their sitting down and their rising up. I am their song.', pt: 'Observa-os ao assentarem-se e ao levantarem-se; eu sou a sua canção.' },
      { v: 64, en: 'You will pay them back, Yahweh, according to the work of their hands.', pt: 'Tu lhes darás a recompensa, Senhor, conforme a obra das suas mãos.' },
      { v: 65, en: 'You will give them hardness of heart, your curse to them.', pt: 'Tu lhes darás dureza de coração, maldição tua sobre eles.' },
      { v: 66, en: 'You will pursue them in anger, and destroy them from under the heavens of Yahweh.', pt: 'Na tua ira os perseguirás, e os destruirás de debaixo dos teus céus, ó Senhor.' },
    ],
    4: [
      { v: 1, en: 'How the gold has become dim! The most pure gold has changed! The stones of the sanctuary are poured out at the head of every street.', pt: 'Como se escureceu o ouro! como se mudou o ouro puríssimo! como estão espalhadas as pedras do santuário pelas esquinas de todas as ruas!' },
      { v: 2, en: 'The precious sons of Zion, comparable to fine gold, how are they esteemed as earthen pitchers, the work of the hands of the potter!', pt: 'Os preciosos filhos de Sião, comparáveis a ouro puro, como são agora reputados por vasos de barro, obra das mãos de oleiro!' },
      { v: 3, en: 'Even the jackals offer their breast. They nurse their young ones. But the daughter of my people has become cruel, like the ostriches in the wilderness.', pt: 'Até os chacais abaixam o peito, dão de mamar aos seus filhos; mas a filha do meu povo tornou-se cruel como os avestruzes no deserto.' },
      { v: 4, en: 'The tongue of the nursing child clings to the roof of his mouth for thirst. The young children ask bread, and no one breaks it for them.', pt: 'A língua do que mama fica pegada pela sede ao seu paladar; os meninos pedem pão, e ninguém lho reparte.' },
      { v: 5, en: 'Those who ate delicacies are desolate in the streets. Those who were brought up in purple embrace dunghills.', pt: 'Os que comiam iguarias delicadas desfalecem nas ruas; os que se criavam em escarlata abraçam monturos.' },
      { v: 6, en: 'For the iniquity of the daughter of my people is greater than the sin of Sodom, which was overthrown as in a moment. No hands were laid on her.', pt: 'Pois maior é a iniqüidade da filha do meu povo do que o pecado de Sodoma, a qual foi subvertida como num momento, sem que mão alguma lhe tocasse.' },
      { v: 7, en: 'Her nobles were purer than snow. They were whiter than milk. They were more ruddy in body than rubies. Their polishing was like sapphire.', pt: 'Os seus nobres eram mais alvos do que a neve, mais brancos do que o leite, eram mais ruivos de corpo do que o coral, e a sua formosura era como a de safira.' },
      { v: 8, en: 'Their appearance is blacker than a coal. They are not known in the streets. Their skin clings to their bones. It is withered. It has become like a stick.', pt: 'Mas agora escureceu-se o seu parecer mais do que o negrume; eles não são reconhecidos nas ruas; a sua pele se lhes pegou aos ossos; secou-se, tornou-se como um pau. .' },
      { v: 9, en: 'Those who are killed with the sword are better than those who are killed with hunger; For these pine away, stricken through, for lack of the fruits of the field.', pt: 'Os mortos à espada eram mais ditosos do que os mortos à fome, pois estes se esgotavam, como traspassados, por falta dos frutos dos campos.' },
      { v: 10, en: 'The hands of the pitiful women have boiled their own children. They were their food in the destruction of the daughter of my people.', pt: 'As mãos das mulheres compassivas cozeram os próprios filhos; estes lhes serviram de alimento na destruição da filha do meu povo.' },
      { v: 11, en: 'Yahweh has accomplished his wrath. He has poured out his fierce anger. He has kindled a fire in Zion, which has devoured its foundations.', pt: 'Deu o Senhor cumprimento ao seu furor, derramou o ardor da sua ira; e acendeu um fogo em Sião, que consumiu os seus fundamentos.' },
      { v: 12, en: 'The kings of the earth didn’t believe, neither did all the inhabitants of the world, that the adversary and the enemy would enter into the gates of Jerusalem.', pt: 'Não creram os reis da terra, bem como nenhum dos moradores do mundo, que adversário ou inimigo pudesse entrar pelas portas de Jerusalém.' },
      { v: 13, en: 'It is because of the sins of her prophets and the iniquities of her priests, That have shed the blood of the just in the middle of her.', pt: 'Isso foi por causa dos pecados dos seus profetas e das iniqüidades dos seus sacerdotes, que derramaram no meio dela o sangue dos justos.' },
      { v: 14, en: 'They wander as blind men in the streets. They are polluted with blood, So that men can’t touch their garments.', pt: 'Vagueiam como cegos pelas ruas; andam contaminados de sangue, de tal sorte que não se lhes pode tocar nas roupas.' },
      { v: 15, en: '“Go away!” they cried to them. “Unclean! Go away! Go away! Don’t touch! When they fled away and wandered, men said among the nations, “They can’t live here any more.”', pt: 'Desviai-vos! imundo! gritavam-lhes; desviai-vos, desviai-vos, não toqueis! Quando fugiram, e andaram, vagueando, dizia-se entre as nações: Nunca mais morarão aqui.' },
      { v: 16, en: 'Yahweh’s anger has scattered them. He will not pay attention to them any more. They didn’t respect the persons of the priests. They didn’t favor the elders.', pt: 'A ira do Senhor os espalhou; ele nunca mais tornará a olhar para eles; não respeitaram a pessoa dos sacerdotes, nem se compadeceram dos velhos.' },
      { v: 17, en: 'Our eyes still fail, looking in vain for our help. In our watching we have watched for a nation that could not save.', pt: 'Os nossos olhos desfaleciam, esperando o nosso vão socorro. em vigiando olhávamos para uma nação, que não podia, livrai.' },
      { v: 18, en: 'They hunt our steps, so that we can’t go in our streets. Our end is near. Our days are fulfilled, for our end has come.', pt: 'Espiaram os nossos passos, de maneira que não podíamos andar pelas nossas ruas; o nosso fim estava perto; estavam contados os nossos dias, porque era chegado o nosso fim.' },
      { v: 19, en: 'Our pursuers were swifter than the eagles of the sky. They chased us on the mountains. They set an ambush for us in the wilderness.', pt: 'Os nossos perseguidores foram mais ligeiros do que as águias do céu; sobre os montes nos perseguiram, no deserto nos armaram ciladas.' },
      { v: 20, en: 'The breath of our nostrils, the anointed of Yahweh, was taken in their pits; of whom we said, under his shadow we will live among the nations.', pt: 'O fôlego da nossa vida, o ungido do Senhor, foi preso nas covas deles, o mesmo de quem dizíamos: Debaixo da sua sombra viveremos entre as nações.' },
      { v: 21, en: 'Rejoice and be glad, daughter of Edom, that dwells in the land of Uz. The cup will pass through to you also. You will be drunken, and will make yourself naked.', pt: 'Regozija-te, e alegra-te, ó filha de Edom, que habitas na terra de Uz; o cálice te passará a ti também; embebedar-te-ás, e te descobrirás.' },
      { v: 22, en: 'The punishment of your iniquity is accomplished, daughter of Zion. He will no more carry you away into captivity. He will visit your iniquity, daughter of Edom. He will uncover your sins.', pt: 'Já se cumpriu o castigo da tua iniqüidade, ó filha de Sião; ele nunca mais te levará para o cativeiro; ele visitará a tua iniqüidade, ó filha de Edom; descobrirá os teus pecados.' },
    ],
    5: [
      { v: 1, en: 'Remember, Yahweh, what has come on us. Look, and see our reproach.', pt: 'Lembra-te, Senhor, do que nos tem sucedido; considera, e olha para o nosso opróbrio.' },
      { v: 2, en: 'Our inheritance has been turned over to strangers, our houses to aliens.', pt: 'A nossa herdade passou a estranhos, e as nossas casas a forasteiros.' },
      { v: 3, en: 'We are orphans and fatherless. Our mothers are as widows.', pt: 'çrfãos somos sem pai, nossas mães são como viuvas.' },
      { v: 4, en: 'We have drunken our water for money. Our wood is sold to us.', pt: 'A nossa água por dinheiro a bebemos, por preço vem a nossa lenha.' },
      { v: 5, en: 'Our pursuers are on our necks. We are weary, and have no rest.', pt: 'Os nossos perseguidores estão sobre os nossos pescoços; estamos cansados, e não temos descanso.' },
      { v: 6, en: 'We have given our hands to the Egyptians, and to the Assyrians, to be satisfied with bread.', pt: 'Aos egípcios e aos assírios estendemos as mãos, para nos fartarmos de pão.' },
      { v: 7, en: 'Our fathers sinned, and are no more. We have borne their iniquities.', pt: 'Nossos pais pecaram, e já não existem; e nós levamos as suas iniqüidades.' },
      { v: 8, en: 'Servants rule over us. There is no one to deliver us out of their hand.', pt: 'Escravos dominam sobre nós; ninguém há que nos arranque da sua mão.' },
      { v: 9, en: 'We get our bread at the peril of our lives, because of the sword of the wilderness.', pt: 'Com perigo de nossas vidas obtemos o nosso pão, por causa da espada do deserto.' },
      { v: 10, en: 'Our skin is black like an oven, because of the burning heat of famine.', pt: 'Nossa pele está abraseada como um forno, por causa do ardor da fome.' },
      { v: 11, en: 'They ravished the women in Zion, the virgins in the cities of Judah.', pt: 'Forçaram as mulheres em Sião, as virgens nas cidades de Judá.' },
      { v: 12, en: 'Princes were hanged up by their hands. The faces of elders were not honored.', pt: 'Príncipes foram enforcados pelas mãos deles; as faces dos anciãos não foram respeitadas.' },
      { v: 13, en: 'The young men carry millstones. The children stumbled under loads of wood.', pt: 'Mancebos levaram a mó; meninos tropeçaram sob fardos de lenha.' },
      { v: 14, en: 'The elders have ceased from the gate, and the young men from their music.', pt: 'Os velhos já não se assentam nas portas, os mancebos já não cantam.' },
      { v: 15, en: 'The joy of our heart has ceased. Our dance is turned into mourning.', pt: 'Cessou o gozo de nosso coração; converteu-se em lamentação a nossa dança.' },
      { v: 16, en: 'The crown has fallen from our head. Woe to us, for we have sinned!', pt: 'Caiu a coroa da nossa cabeça; ai de nós. porque pecamos.' },
      { v: 17, en: 'For this our heart is faint. For these things our eyes are dim.', pt: 'Portanto desmaiou o nosso coração; por isso se escureceram os nossos olhos.' },
      { v: 18, en: 'For the mountain of Zion, which is desolate. The foxes walk on it.', pt: 'Pelo monte de Sião, que está assolado, andam os chacais.' },
      { v: 19, en: 'You, Yahweh, remain forever. Your throne is from generation to generation.', pt: 'Tu, Senhor, permaneces eternamente; e o teu trono subsiste de geração em geração.' },
      { v: 20, en: 'Why do you forget us forever, and forsake us for so long a time?', pt: 'Por que te esquecerias de nós para sempre, por que nos desampararias por tanto tempo?' },
      { v: 21, en: 'Turn us to yourself, Yahweh, and we will be turned. Renew our days as of old.', pt: 'Converte-nos a ti, Senhor, e seremos convertidos; renova os nossos dias como dantes;' },
      { v: 22, en: 'But you have utterly rejected us. You are very angry against us.', pt: 'se é que não nos tens de todo rejeitado, se é que não estás sobremaneira irado contra nos.' },
    ],
  },
};

export default book;
